import React, { createContext, useContext, useState } from 'react';
import { v4 as uuidv4 } from 'uuid';

const TokenContext = createContext();

export const TokenProvider = ({ children }) => {
  const [token, setToken] = useState(null);

  const generateToken = () => {
    setToken(uuidv4());
  };

  return (
    <TokenContext.Provider value={{ token, generateToken }}>
      {children}
    </TokenContext.Provider>
  );
};

export const useToken = () => useContext(TokenContext);

// In your component where you want to generate a token
import React, { useEffect } from 'react';
import { NetInfo } from '@react-native-community/netinfo';
import { useToken } from './TokenProvider';

const OfflineComponent = () => {
  const { generateToken, token } = useToken();
  const netInfo = NetInfo.useNetInfo();

  useEffect(() => {
    if (!netInfo.isConnected) {
      generateToken();
    }
  }, [netInfo.isConnected]);

  return (
    <View>
      {token && <Text>Your token is: {token}</Text>}
      {!token && <Text>No internet connection, please check your network.</Text>}
    </View>
  );
};

export default OfflineComponent;